  1→//! Live MCP service implementation backed by `McpManager`.
  2→
  3→use std::{collections::HashMap, sync::Arc};
  4→
  5→use {
  6→    anyhow::Result,
  7→    async_trait::async_trait,
  8→    secrecy::{ExposeSecret, Secret},
  9→    serde_json::Value,
 10→    tokio::sync::RwLock,
 11→    tracing::{info, warn},
 12→};
 13→
 14→use {
 15→    moltis_agents::tool_registry::{AgentTool, ToolRegistry},
 16→    moltis_mcp::tool_bridge::{McpAgentTool, McpToolBridge},
 17→};
 18→
 19→use crate::services::{McpService, ServiceError, ServiceResult};
 20→
 21→// ── McpToolAdapter: bridge McpAgentTool → AgentTool ─────────────────────────
 22→
 23→/// Thin adapter that implements `AgentTool` (agents crate) by delegating to
 24→/// `McpToolBridge` which implements `McpAgentTool` (mcp crate).
 25→struct McpToolAdapter(McpToolBridge);
 26→
 27→#[async_trait]
 28→impl AgentTool for McpToolAdapter {
 29→    fn name(&self) -> &str {
 30→        McpAgentTool::name(&self.0)
 31→    }
 32→
 33→    fn description(&self) -> &str {
 34→        McpAgentTool::description(&self.0)
 35→    }
 36→
 37→    fn parameters_schema(&self) -> Value {
 38→        McpAgentTool::parameters_schema(&self.0)
 39→    }
 40→
 41→    async fn execute(&self, params: Value) -> Result<Value> {
 42→        McpAgentTool::execute(&self.0, params)
 43→            .await
 44→            .map_err(anyhow::Error::from)
 45→    }
 46→}
 47→
 48→// ── Sync helper ─────────────────────────────────────────────────────────────
 49→
 50→/// Synchronize MCP tool bridges into the shared `ToolRegistry`.
 51→///
 52→/// Removes all existing `mcp__*` tools and re-registers current bridges.
 53→pub async fn sync_mcp_tools(
 54→    manager: &moltis_mcp::McpManager,
 55→    registry: &Arc<RwLock<ToolRegistry>>,
 56→) {
 57→    let bridges = manager.tool_bridges().await;
 58→
 59→    let mut reg = registry.write().await;
 60→
 61→    // Remove all MCP-sourced tools before re-registering current ones.
 62→    reg.unregister_mcp();
 63→
 64→    // Register current bridges with their server name metadata.
 65→    let count = bridges.len();
 66→    for bridge in bridges {
 67→        let server = bridge.server_name().to_string();
 68→        reg.register_mcp(Box::new(McpToolAdapter(bridge)), server);
 69→    }
 70→
 71→    if count > 0 {
 72→        info!(tools = count, "MCP tools synced into tool registry");
 73→    }
 74→}
 75→
 76→// ── Config parsing helper ───────────────────────────────────────────────────
 77→
 78→/// Extract an `McpServerConfig` from JSON params.
 79→///
 80→/// For updates, omitted fields inherit from `existing`.
 81→fn parse_server_config(
 82→    params: &Value,
 83→    existing: Option<&moltis_mcp::McpServerConfig>,
 84→) -> Result<moltis_mcp::McpServerConfig, ServiceError> {
 85→    let transport = match params.get("transport").and_then(|v| v.as_str()) {
 86→        Some("sse") => moltis_mcp::TransportType::Sse,
 87→        Some(_) => moltis_mcp::TransportType::Stdio,
 88→        None => existing
 89→            .map(|cfg| cfg.transport)
 90→            .unwrap_or(moltis_mcp::TransportType::Stdio),
 91→    };
 92→
 93→    let command = params
 94→        .get("command")
 95→        .and_then(|v| v.as_str())
 96→        .map(String::from)
 97→        .or_else(|| existing.map(|cfg| cfg.command.clone()))
 98→        .unwrap_or_default();
 99→
100→    if matches!(transport, moltis_mcp::TransportType::Stdio) && command.trim().is_empty() {
101→        return Err(ServiceError::message("missing 'command' parameter"));
102→    }
103→
104→    let args: Vec<String> = if params.get("args").is_some() {
105→        params
106→            .get("args")
107→            .and_then(|v| serde_json::from_value(v.clone()).ok())
108→            .unwrap_or_default()
109→    } else {
110→        existing.map(|cfg| cfg.args.clone()).unwrap_or_default()
111→    };
112→
113→    let enabled = params
114→        .get("enabled")
115→        .and_then(|v| v.as_bool())
116→        .or_else(|| existing.map(|cfg| cfg.enabled))
117→        .unwrap_or(true);
118→
119→    let url = if params.get("url").is_some() {
120→        if params.get("url").is_some_and(Value::is_null) {
121→            None
122→        } else {
123→            params
124→                .get("url")
125→                .and_then(|v| v.as_str())
126→                .map(|value| Secret::new(value.to_string()))
127→        }
128→    } else {
129→        existing.and_then(|cfg| cfg.url.clone())
130→    };
131→
132→    let headers = if matches!(transport, moltis_mcp::TransportType::Sse) {
133→        if params.get("headers").is_some() {
134→            parse_secret_string_map(params.get("headers").unwrap_or(&Value::Null))
135→        } else {
136→            existing.map(|cfg| cfg.headers.clone()).unwrap_or_default()
137→        }
138→    } else {
139→        HashMap::new()
140→    };
141→
142→    let env = if matches!(transport, moltis_mcp::TransportType::Sse) {
143→        HashMap::new()
144→    } else if params.get("env").is_some() {
145→        parse_string_map(params.get("env").unwrap_or(&Value::Null))
146→    } else {
147→        existing.map(|cfg| cfg.env.clone()).unwrap_or_default()
148→    };
149→
150→    if matches!(transport, moltis_mcp::TransportType::Sse)
151→        && url
152→            .as_ref()
153→            .map(ExposeSecret::expose_secret)
154→            .is_none_or(|candidate| candidate.trim().is_empty())
155→    {
156→        return Err(ServiceError::message(
157→            "missing 'url' parameter for 'sse' transport",
158→        ));
159→    }
160→
161→    let oauth = if let Some(v) = params.get("oauth") {
162→        if v.is_null() {
163→            None
164→        } else {
165→            let client_id = v
166→                .get("client_id")
167→                .and_then(|val| val.as_str())
168→                .ok_or_else(|| ServiceError::message("missing 'oauth.client_id' parameter"))?
169→                .to_string();
170→            let auth_url = v
171→                .get("auth_url")
172→                .and_then(|val| val.as_str())
173→                .ok_or_else(|| ServiceError::message("missing 'oauth.auth_url' parameter"))?
174→                .to_string();
175→            let token_url = v
176→                .get("token_url")
177→                .and_then(|val| val.as_str())
178→                .ok_or_else(|| ServiceError::message("missing 'oauth.token_url' parameter"))?
179→                .to_string();
180→            let scopes: Vec<String> = v
181→                .get("scopes")
182→                .and_then(|s| serde_json::from_value(s.clone()).ok())
183→                .unwrap_or_default();
184→            Some(moltis_mcp::registry::McpOAuthConfig {
185→                client_id,
186→                auth_url,
187→                token_url,
188→                scopes,
189→            })
190→        }
191→    } else {
192→        existing.and_then(|cfg| cfg.oauth.clone())
193→    };
194→
195→    let display_name = match params.get("display_name") {
196→        Some(v) if v.is_null() => None,
197→        Some(v) => v.as_str().map(String::from),
198→        None => existing.and_then(|cfg| cfg.display_name.clone()),
199→    };
200→
201→    Ok(moltis_mcp::McpServerConfig {
202→        command,
203→        args,
204→        env,
205→        enabled,
206→        transport,
207→        url: if matches!(transport, moltis_mcp::TransportType::Sse) {
208→            url
209→        } else {
210→            None
211→        },
212→        headers,
213→        oauth,
214→        display_name,
215→    })
216→}
217→
218→fn parse_string_map(value: &Value) -> HashMap<String, String> {
219→    serde_json::from_value(value.clone()).unwrap_or_default()
220→}
221→
222→fn parse_secret_string_map(value: &Value) -> HashMap<String, Secret<String>> {
223→    parse_string_map(value)
224→        .into_iter()
225→        .map(|(key, value)| (key, Secret::new(value)))
226→        .collect()
227→}
228→
229→// ── LiveMcpService ──────────────────────────────────────────────────────────
230→
231→/// Live MCP service delegating to `McpManager`.
232→pub struct LiveMcpService {
233→    manager: Arc<moltis_mcp::McpManager>,
234→    /// Shared tool registry for syncing MCP tools into the agent loop.
235→    /// Set after construction via `set_tool_registry`.
236→    tool_registry: RwLock<Option<Arc<RwLock<ToolRegistry>>>>,
237→    config_env_overrides: HashMap<String, String>,
238→    credential_store: RwLock<Option<Arc<crate::auth::CredentialStore>>>,
239→}
240→
241→impl LiveMcpService {
242→    pub fn new(
243→        manager: Arc<moltis_mcp::McpManager>,
244→        config_env_overrides: HashMap<String, String>,
245→        credential_store: Option<Arc<crate::auth::CredentialStore>>,
246→    ) -> Self {
247→        Self {
248→            manager,
249→            tool_registry: RwLock::new(None),
250→            config_env_overrides,
251→            credential_store: RwLock::new(credential_store),
252→        }
253→    }
254→
255→    /// Store a reference to the shared tool registry so MCP mutations
256→    /// can automatically sync tools.
257→    pub async fn set_tool_registry(&self, registry: Arc<RwLock<ToolRegistry>>) {
258→        *self.tool_registry.write().await = Some(registry);
259→    }
260→
261→    /// Sync MCP tools into the shared tool registry (if set).
262→    pub async fn sync_tools_if_ready(&self) {
263→        let maybe_reg = self.tool_registry.read().await.clone();
264→        if let Some(reg) = maybe_reg {
265→            sync_mcp_tools(&self.manager, &reg).await;
266→        }
267→    }
268→
269→    /// Access the underlying manager.
270→    pub fn manager(&self) -> &Arc<moltis_mcp::McpManager> {
271→        &self.manager
272→    }
273→
274→    pub async fn set_credential_store(&self, credential_store: Arc<crate::auth::CredentialStore>) {
275→        *self.credential_store.write().await = Some(credential_store);
276→    }
277→
278→    async fn refresh_manager_env_overrides(&self) {
279→        let credential_store = self.credential_store.read().await.clone();
280→        let env_overrides = if let Some(store) = credential_store {
281→            match store.get_all_env_values().await {
282→                Ok(db_env_vars) => merge_env_overrides(&self.config_env_overrides, db_env_vars),
283→                Err(error) => {
284→                    warn!(%error, "failed to refresh MCP env overrides from credential store");
285→                    self.config_env_overrides.clone()
286→                },
287→            }
288→        } else {
289→            self.config_env_overrides.clone()
290→        };
291→
292→        self.manager.set_env_overrides(env_overrides).await;
293→    }
294→}
295→
296→fn merge_env_overrides(
297→    base_overrides: &HashMap<String, String>,
298→    additional: Vec<(String, String)>,
299→) -> HashMap<String, String> {
300→    // Config `[env]` values stay authoritative so checked-in config cannot be
301→    // silently shadowed by mutable UI-managed entries from the credential store.
302→    let mut merged = base_overrides.clone();
303→    for (key, value) in additional {
304→        if key.trim().is_empty() || value.trim().is_empty() {
305→            continue;
306→        }
307→        merged.entry(key).or_insert(value);
308→    }
309→    merged
310→}
311→
312→#[async_trait]
313→impl McpService for LiveMcpService {
314→    async fn list(&self) -> ServiceResult {
315→        let statuses = self.manager.status_all().await;
316→        Ok(serde_json::to_value(&statuses)?)
317→    }
318→
319→    async fn add(&self, params: Value) -> ServiceResult {
320→        let name = params
321→            .get("name")
322→            .and_then(|v| v.as_str())
323→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
324→        let redirect_uri = params
325→            .get("redirectUri")
326→            .and_then(|v| v.as_str())
327→            .map(str::trim)
328→            .filter(|v| !v.is_empty())
329→            .map(ToOwned::to_owned);
330→        let config = parse_server_config(&params, None)?;
331→        self.refresh_manager_env_overrides().await;
332→
333→        // If a server with this name already exists, append a numeric suffix.
334→        let final_name = {
335→            let reg = self.manager.registry_snapshot().await;
336→            let mut candidate = name.to_string();
337→            let mut n = 2u32;
338→            while reg.servers.contains_key(&candidate) {
339→                candidate = format!("{name}-{n}");
340→                n += 1;
341→            }
342→            candidate
343→        };
344→
345→        info!(server = %final_name, "adding MCP server via API");
346→        match self
347→            .manager
348→            .add_server(final_name.clone(), config, true)
349→            .await
350→        {
351→            Ok(_) => {
352→                self.sync_tools_if_ready().await;
353→                Ok(serde_json::json!({ "ok": true, "name": final_name }))
354→            },
355→            Err(e) => {
356→                if matches!(
357→                    e,
358→                    moltis_mcp::Error::Manager(moltis_mcp::McpManagerError::OAuthRequired { .. })
359→                ) {
360→                    if let Some(uri) = redirect_uri {
361→                        let auth_url = self
362→                            .manager
363→                            .oauth_start_server(&final_name, &uri)
364→                            .await
365→                            .map_err(ServiceError::message)?;
366→                        Ok(serde_json::json!({
367→                            "ok": true,
368→                            "name": final_name,
369→                            "oauthPending": true,
370→                            "authUrl": auth_url
371→                        }))
372→                    } else {
373→                        Ok(serde_json::json!({
374→                            "ok": true,
375→                            "name": final_name,
376→                            "oauthPending": true
377→                        }))
378→                    }
379→                } else {
380→                    Err(ServiceError::message(e))
381→                }
382→            },
383→        }
384→    }
385→
386→    async fn remove(&self, params: Value) -> ServiceResult {
387→        let name = params
388→            .get("name")
389→            .and_then(|v| v.as_str())
390→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
391→
392→        let removed = self
393→            .manager
394→            .remove_server(name)
395→            .await
396→            .map_err(ServiceError::message)?;
397→
398→        self.sync_tools_if_ready().await;
399→
400→        Ok(serde_json::json!({ "removed": removed }))
401→    }
402→
403→    async fn enable(&self, params: Value) -> ServiceResult {
404→        let name = params
405→            .get("name")
406→            .and_then(|v| v.as_str())
407→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
408→        let redirect_uri = params
409→            .get("redirectUri")
410→            .and_then(|v| v.as_str())
411→            .map(str::trim)
412→            .filter(|v| !v.is_empty())
413→            .map(ToOwned::to_owned);
414→        self.refresh_manager_env_overrides().await;
415→
416→        match self.manager.enable_server(name).await {
417→            Ok(_) => {
418→                self.sync_tools_if_ready().await;
419→                Ok(serde_json::json!({ "enabled": true }))
420→            },
421→            Err(e) => {
422→                if matches!(
423→                    e,
424→                    moltis_mcp::Error::Manager(moltis_mcp::McpManagerError::OAuthRequired { .. })
425→                ) {
426→                    if let Some(uri) = redirect_uri {
427→                        let auth_url = self
428→                            .manager
429→                            .oauth_start_server(name, &uri)
430→                            .await
431→                            .map_err(ServiceError::message)?;
432→                        Ok(serde_json::json!({
433→                            "enabled": false,
434→                            "oauthPending": true,
435→                            "authUrl": auth_url
436→                        }))
437→                    } else {
438→                        Ok(serde_json::json!({
439→                            "enabled": false,
440→                            "oauthPending": true
441→                        }))
442→                    }
443→                } else {
444→                    Err(ServiceError::message(e))
445→                }
446→            },
447→        }
448→    }
449→
450→    async fn disable(&self, params: Value) -> ServiceResult {
451→        let name = params
452→            .get("name")
453→            .and_then(|v| v.as_str())
454→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
455→
456→        let ok = self
457→            .manager
458→            .disable_server(name)
459→            .await
460→            .map_err(ServiceError::message)?;
461→
462→        self.sync_tools_if_ready().await;
463→
464→        Ok(serde_json::json!({ "disabled": ok }))
465→    }
466→
467→    async fn status(&self, params: Value) -> ServiceResult {
468→        let name = params
469→            .get("name")
470→            .and_then(|v| v.as_str())
471→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
472→
473→        match self.manager.status(name).await {
474→            Some(s) => Ok(serde_json::to_value(&s)?),
475→            None => Err(format!("MCP server '{name}' not found").into()),
476→        }
477→    }
478→
479→    async fn tools(&self, params: Value) -> ServiceResult {
480→        let name = params
481→            .get("name")
482→            .and_then(|v| v.as_str())
483→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
484→
485→        match self.manager.server_tools(name).await {
486→            Some(tools) => Ok(serde_json::to_value(&tools)?),
487→            None => Err(format!("MCP server '{name}' not found or not running").into()),
488→        }
489→    }
490→
491→    async fn restart(&self, params: Value) -> ServiceResult {
492→        let name = params
493→            .get("name")
494→            .and_then(|v| v.as_str())
495→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
496→        self.refresh_manager_env_overrides().await;
497→
498→        self.manager
499→            .restart_server(name)
500→            .await
501→            .map_err(ServiceError::message)?;
502→
503→        self.sync_tools_if_ready().await;
504→
505→        Ok(serde_json::json!({ "ok": true }))
506→    }
507→
508→    async fn update(&self, params: Value) -> ServiceResult {
509→        let name = params
510→            .get("name")
511→            .and_then(|v| v.as_str())
512→            .ok_or_else(|| "missing 'name' parameter".to_string())?;
513→        let existing = self
